#include <stdio.h>
#include <stdbool.h>
#include <string.h>

#define MAX_ATTRS 10
#define MAX_FDS 20

typedef struct {
    char attributes[MAX_ATTRS][20];
    int count;
} AttributeSet;

typedef struct {
    AttributeSet determinant;  // X in X->Y
    AttributeSet dependent;    // Y in X->Y
} FunctionalDependency;

// Check if set A is subset of set B
bool isSubset(AttributeSet A, AttributeSet B) {
    for (int i = 0; i < A.count; i++) {
        bool found = false;
        for (int j = 0; j < B.count; j++) {
            if (strcmp(A.attributes[i], B.attributes[j]) == 0) {
                found = true;
                break;
            }
        }
        if (!found) return false;
    }
    return true;
}

// Check if relation is in BCNF
bool isInBCNF(AttributeSet allAttrs, FunctionalDependency fds[], int fdCount) {
    for (int i = 0; i < fdCount; i++) {
        // For BCNF: determinant must be a superkey
        // Check if determinant can determine all attributes
        AttributeSet closure = fds[i].determinant;

        // Simplified: check if determinant == all attributes
        // (In practice, compute closure using all FDs)
        if (!isSubset(allAttrs, fds[i].determinant) && 
            fds[i].determinant.count != allAttrs.count) {
            printf("Violates BCNF: ");
            for (int j = 0; j < fds[i].determinant.count; j++)
                printf("%s ", fds[i].determinant.attributes[j]);
            printf("-> ");
            for (int j = 0; j < fds[i].dependent.count; j++)
                printf("%s ", fds[i].dependent.attributes[j]);
            printf(" is not a superkey\n");
            return false;
        }
    }
    return true;
}

int main() {
    // Example: R(A, B, C) with FD: B -> C
    // B is not a superkey (key is AB)
    // This violates BCNF

    AttributeSet allAttrs = {{"A", "B", "C"}, 3};
    FunctionalDependency fds[1];
    fds[0].determinant = {{"B"}, 1};
    fds[0].dependent = {{"C"}, 1};

    if (isInBCNF(allAttrs, fds, 1))
        printf("Relation is in BCNF\n");
    else
        printf("Relation is NOT in BCNF\n");

    return 0;
}
